11	// MachineConfigPoolBuilder provides a more fluent API for creating
12	// MachineConfigPool objects for tests. Instead of creating multiple specific
13	// functions for each particular node configuration, this allows one to create
14	// nodes thusly:
15	//
16	// NewMachineConfigPoolBuilder("worker").WithMachineConfig(currentConfig).MachineConfigPool()
17	//
18	// It is aware of the rules around creating layering-enabled
19	// MachineConfigPools. For example, if one sets an image with the WithImage()
20	// method, it will automatically set the layering annotation.
21	type MachineConfigPoolBuilder struct {
22		name           string
